INSERT INTO bot_respuestas (id_empresa, tipo, disparador, mensaje, estado) VALUES
(1, 'PALABRA_CLAVE', 'precio, precios, costo, valor, cuanto cuesta, presupuesto', 'Nuestros precios varían según el servicio que requieras. Para una cotización exacta, un asesor se comunicará contigo enseguida. Mientras tanto, puedes conocer más en nuestro sitio web.', 'ACTIVO'),
(1, 'PALABRA_CLAVE', 'ubicacion, donde estan, direccion, oficina', 'Nuestra sede principal se encuentra en la Av. Principal, Edificio Empresarial, Piso 3. ¡Estaremos encantados de recibirte en nuestras oficinas!', 'ACTIVO'),
(1, 'PALABRA_CLAVE', 'horario, horas, a que hora abren, trabajan los fines de semana', 'Nuestro horario de atención al cliente es de Lunes a Viernes, de 8:00 AM a 5:00 PM (Hora local).', 'ACTIVO'),
(1, 'PALABRA_CLAVE', 'soporte, ayuda, problema, falla, no funciona', 'Lamentamos el inconveniente. Hemos derivado tu caso al equipo técnico y te contactarán a la brevedad posible para brindarte soporte.', 'ACTIVO'),
(1, 'PALABRA_CLAVE', 'gracias, excelente, muy amable, ok, perfecto, vale', '¡A ti por preferirnos! Estamos siempre a tu disposición para lo que necesites. ¡Que tengas un excelente día!', 'ACTIVO');
